#include <bits/stdc++.h>
using namespace std;
struct xt {
	int a[15],th;
	double ave;
} t[105];
bool cmp(xt a,xt b){
	if(a.ave==b.ave){
		return a.th<b.th;
	}
	return a.ave>b.ave;
}
long long a,b;
int main() {
	cin>>a>>b;
	for(int i=1; i<=a; i++) {
		t[i].ave=0;
		t[i].th=i;
		for(int j=1; j<=b; j++) {
			cin>>t[i].a[j];
			t[i].ave+=t[i].a[j];
		}
		t[i].ave/=b;
	}
	sort(t+1,t+a+1,cmp);
	cout<<t[1].th<<"\n"<<t[2].th;
	return 0;
}
